"""
MKT Original Language Commentary — Romans chapters 15–16
Run: python3 scripts/zc-original-romans-15-16.py

Source data used:
- data/interlinear/romans.json
- data/translation/glossary-greek.json (diakonia G1249 disp=2, pistis G4102 disp=3,
  logos G3056 disp=3, pneuma G4151 disp=3, aiōnios G166 disp=3)
- data/translation/notes/romans.json
- data/translation/draft/mediating/romans.json
- data/commentary/ellicott/romans.json (reference for 15:16 and 16:7 debates)
- data/commentary/mkt-original/romans.json (continuity: read ch.1-3 before writing)

Key decisions in this range:
- 15:16 leitourgon / hierourgounta — both are cultic/liturgical vocabulary; Paul
  deliberately frames his mission in priestly terms, with Gentile converts as the
  offering. Commentary notes both terms without conflating liturgical and missionary.
- 16:1 diakonon — the Greek word is the same form regardless of the referent's gender;
  there is no feminine of diakonos in first-century use. Commentary treats Phoebe as
  holding the same diakonos role described in Phil 1:1 and 1 Tim 3:8-13.
- 16:7 Iounian — the name form is ambiguous between Junia (female, common Roman name)
  and Junias (male, unattested as a name in the ancient world). Modern text-critical
  consensus favors Junia. Commentary notes the debate and the two options for
  episēmoi en tois apostolois (outstanding among vs. well-known to the apostles).
- 16:25-27 doxology — the placement of this doxology varies across manuscripts (some
  place it at end of ch.14, some at end of ch.15, some at both). Commentary notes
  this briefly; the content grounds the letter's themes.
- Terminology continuity from ch.1-3: diakonos (servant/deacon, not "minister" in
  the ecclesial hierarchy sense), charis (grace), leitourgos (liturgical servant),
  koinōnia (fellowship/participation with financial-sharing dimension).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "15": {
    "1": '<p><strong>ὀφείλομεν</strong> (we are obligated, G3784) — the verb is of debt and moral necessity, not mere preference. Paul includes himself in the "we who are strong," establishing that the obligation to bear with the weak is a defining characteristic of the strong, not a concession they may choose to make. <strong>βαστάζειν</strong> (to carry, bear, G941) — the infinitive of purpose; the same verb used for carrying burdens in Gal 6:2, where it describes mutual burden-bearing in the community.</p>',
    "2": '<p><strong>ἕκαστος ἡμῶν τῷ πλησίον ἀρεσκέτω</strong> (let each of us please his neighbor) — present imperative: an ongoing obligation. <strong>εἰς οἰκοδομήν</strong> (for building up, G3619) — the construction metaphor that runs through Paul\'s ethics; pleasing the neighbor is not mere social compliance but serves the architectural goal of the community\'s flourishing. The phrase <em>eis to agathon</em> (for the good) qualifies <em>areskō</em> — pleasing must be directed toward actual good, not flattery.</p>',
    "3": '<p><strong>καὶ γὰρ ὁ Χριστὸς οὐχ ἑαυτῷ ἤρεσεν</strong> (for Christ himself did not please himself) — aorist indicative: a completed historical act. The negative is emphatic; Christ\'s whole Incarnation and Passion is described as a sustained refusal of self-pleasing. <strong>τοῦ μὴ ἀρέσαι ἑαυτῷ</strong> — articular infinitive used as substantive subject of the quotation\'s application: the result of Christ\'s not-pleasing-himself is the weight of others\' insults falling on him (Ps 69:9 LXX).</p>',
    "4": '<p><strong>ὅσα γὰρ προεγράφη</strong> (whatever was written beforehand, G4270) — aorist passive of <em>prographō</em>; the divine passive indicates God as the author of Scripture\'s purpose. <strong>εἰς τὴν ἡμετέραν διδασκαλίαν ἐγράφη</strong> (was written for our instruction) — another aorist passive; the purpose is explicitly pedagogical for the present community. <strong>διὰ τῆς ὑπομονῆς καὶ διὰ τῆς παρακλήσεως τῶν γραφῶν</strong> — through the patient endurance and the encouragement of the Scriptures; the genitives are subjective: Scripture itself produces these qualities in the reader.</p>',
    "5": '<p><strong>ὁ θεὸς τῆς ὑπομονῆς καὶ τῆς παρακλήσεως</strong> (the God of endurance and encouragement) — Paul\'s characteristic way of naming God by the gifts he gives; the same divine attributes that the Scriptures produce (v.4) are sourced in God\'s own character. <strong>τὸ αὐτὸ φρονεῖν ἐν ἀλλήλοις κατὰ Χριστὸν Ἰησοῦν</strong> (to think the same thing toward one another according to Christ Jesus) — <em>phroneo</em> (to think/be minded, G5426) is the attitude/disposition verb Paul uses throughout Phil 2; the unity requested is not intellectual uniformity but the same orientation toward the other.</p>',
    "6": '<p><strong>ὁμοθυμαδόν</strong> (with one accord, G3661) — a compound adverb built from <em>homos</em> (same) + <em>thymos</em> (passionate impulse, spirit); it appears frequently in Acts for the gathered community. The word describes a unified orientation of the will, not merely coordinated action. <strong>ἐν ἑνὶ στόματι</strong> (with one mouth) — the communal worship that results from the unified disposition; the glorification is verbal and liturgical, not merely attitudinal.</p>',
    "7": '<p><strong>προσλαμβάνεσθε ἀλλήλους</strong> (receive/accept one another, G4355) — present middle imperative: the receiving is to be an active, ongoing practice. The same verb appears at 14:1 and 14:3 where God\'s receiving of both weak and strong is the ground for mutual acceptance. <strong>καθὼς καὶ ὁ Χριστὸς προσελάβετο ὑμᾶς</strong> (just as Christ received you) — aorist: a single completed act that defines the character of the community\'s ongoing receiving of each other.</p>',
    "8": '<p><strong>διάκονον γεγενῆσθαι περιτομῆς</strong> (to have become a servant/deacon of the circumcised, G1249) — the perfect infinitive indicates an ongoing resultant state; Christ\'s Incarnation placed him in the continuing role of servant to Israel. <em>Diakonos</em> here is the same word used for Phoebe in 16:1 — a functionary serving a community\'s need. <strong>ὑπὲρ ἀληθείας θεοῦ</strong> (on behalf of God\'s truth) — genitive of the beneficiary; the mission to Israel serves the integrity of God\'s own covenant word.</p><p><strong>εἰς τὸ βεβαιῶσαι τὰς ἐπαγγελίας τῶν πατέρων</strong> (to confirm the promises to the patriarchs, G950) — articular infinitive of purpose; <em>bebaiōsai</em> (to make firm, establish) is the verb for confirming a guarantee. Christ\'s mission to Israel was not a postponed mission to Gentiles but the necessary fulfillment of covenant promises that then opened the way for the Gentiles.</p>',
    "9": '<p><strong>ὑπὲρ ἐλέους</strong> (on behalf of/for mercy, G1656) — here the Gentile glorification is grounded in God\'s mercy, contrasted with Israel\'s covenant-promise ground (v.8); both are reasons for the single mission. <strong>ἐξομολογήσομαί σοι ἐν ἔθνεσιν</strong> (I will praise you among the Gentiles) — future middle of <em>exomologeō</em>; the quotation from Ps 18:49/2 Sam 22:50 places the Davidic king among the nations in praise, which Paul reads as a messianic figure whose praise extends Israel\'s worship into Gentile territory.</p>',
    "10": '<p>The quotation from Deut 32:43 (the Song of Moses) — <strong>εὐφράνθητε, ἔθνη, μετὰ τοῦ λαοῦ αὐτοῦ</strong> (rejoice, Gentiles, with his people) — is a call for Gentile participation in Israel\'s covenantal joy. Moses\'s own closing poem already envisioned Gentiles rejoicing alongside Israel; Paul reads this as anticipation of the Gentile mission (cf. 10:19 where he quotes Deut 32:21 from the same poem).</p>',
    "11": '<p>Ps 117:1 (LXX 116:1) — <strong>αἰνεῖτε τὸν κύριον πάντα τὰ ἔθνη</strong> (praise the Lord all the Gentiles) — the shortest psalm and the broadest invitation; Paul uses it as a third OT witness to Gentile worship. The fourfold OT catena (vv.9-12) from Psalms, Deuteronomy, Psalms, Isaiah demonstrates that the Gentile mission is not an afterthought but the convergence of multiple scriptural promises.</p>',
    "12": '<p><strong>ἡ ῥίζα τοῦ Ἰεσσαί</strong> (the root of Jesse) — Paul quotes Isa 11:10 LXX; the Hebrew of Isa 11:10 has "root of Jesse" as a banner/signal, but the LXX (and Paul) read it as the one who rises up to rule. <strong>ὁ ἀνιστάμενος ἄρχειν ἐθνῶν</strong> (the one who rises to rule over the nations) — <em>anistamenos</em> is a present middle participle that can carry the double sense of rising geographically and rising from death; Paul may intend both the Messiah\'s reign and his resurrection as the ground of Gentile hope.</p>',
    "13": '<p><strong>ὁ θεὸς τῆς ἐλπίδος</strong> (the God of hope, G1680) — the title summarizes the OT catena just completed: the God whose promises to patriarchs, Psalms, Deuteronomy, and Isaiah all pointed toward the hope now declared. <strong>πληρώσαι ὑμᾶς πάσης χαρᾶς καὶ εἰρήνης ἐν τῷ πιστεύειν</strong> (may he fill you with all joy and peace in believing) — aorist optative: the wish-prayer form; <em>en tō pisteuein</em> locates the filling within the ongoing act of trust. <strong>εἰς τὸ περισσεύειν ὑμᾶς ἐν τῇ ἐλπίδι</strong> (so that you overflow in hope) — <em>perisseuein</em> (G4052) is not merely having hope but brimming over with it; the goal of filling is abundance beyond sufficiency. <strong>ἐν δυνάμει πνεύματος ἁγίου</strong> (by power of the Holy Spirit) — the Spirit is the agent of the overflowing.</p>',
    "14": '<p><strong>πεπληρωμένοι πάσης γνώσεως</strong> (filled with all knowledge, G1108) — the perfect passive participle indicates a standing state, not a process being initiated; Paul is not starting the Roman community\'s education but confirming what is already present. <strong>νουθετεῖν ἀλλήλους</strong> (to admonish/counsel one another, G3560) — <em>noutheteō</em> is a strong verb for corrective guidance; it implies both knowledge of the standard and will to apply it in the community context.</p>',
    "15": '<p><strong>τολμηρότερον</strong> (quite boldly, comparative adverb, G5112) — the comparative form is an acknowledgment that some parts of the letter have pushed beyond courteous encouragement into frank challenge. <strong>ὡς ἐπαναμιμνῄσκων ὑμᾶς</strong> (as reminding you) — the participle frames Paul\'s letter as re-activating knowledge already possessed, not imposing foreign doctrine. <strong>διὰ τὴν χάριν τὴν δοθεῖσάν μοι</strong> (because of the grace given to me) — the aorist passive participle marks the apostolic commission as a gift received, not an authority self-claimed; cf. the same formula at Rom 12:3 and 1 Cor 3:10.</p>',
    "16": '<p><strong>λειτουργὸν Χριστοῦ Ἰησοῦ</strong> (liturgical servant/minister of Christ Jesus, G3011) — <em>leitourgos</em> is a civic and religious term for one who performs public service at their own expense; it carries cultic/priestly resonance. Paul frames his apostolic role in priestly vocabulary to ground what follows. <strong>ἱερουργοῦντα τὸ εὐαγγέλιον</strong> (performing priestly service with/for the gospel, G2418) — <em>hierourgeō</em> is a hapax in the NT; it means to handle something as a priest handles the sacred. The gospel is the sacred object of Paul\'s priestly service.</p><p><strong>ἡ προσφορὰ τῶν ἐθνῶν</strong> (the offering of the Gentiles, G4376) — an ambiguous genitive: the Gentiles as the offering (objective), or the offering that the Gentiles bring (subjective). The context suggests the objective reading: Paul presents the converted Gentiles to God as a priestly offering. <strong>εὐπρόσδεκτος ἡγιασμένη ἐν πνεύματι ἁγίῳ</strong> (acceptable, sanctified by the Holy Spirit) — the Spirit performs the sanctification that makes the human offering acceptable, taking over the role the altar ritual performed for animal offerings.</p>',
    "17": '<p><strong>τὴν καύχησιν ἐν Χριστῷ Ἰησοῦ</strong> (the boasting in Christ Jesus) — Paul\'s boasting is qualified by its location: not in his own achievements but in Christ. The dative <em>en Christō</em> specifies the sphere; his basis for glory is Christ\'s work, not his own. <strong>τὰ πρὸς τὸν θεόν</strong> (the things toward God) — the specific domain of his priestly role (cf. Heb 2:17; 5:1).</p>',
    "18": '<p><strong>οὐ γὰρ τολμήσω τι λαλεῖν ὧν οὐ κατειργάσατο Χριστὸς δι᾽ ἐμοῦ</strong> (I will not dare to speak of anything except what Christ accomplished through me) — the double negative creates emphatic restriction; Paul\'s preaching authority is entirely derivative. <strong>κατειργάσατο</strong> (aorist middle = accomplished, G2716) — Christ is the subject; Paul is the instrument. <strong>εἰς ὑπακοὴν ἐθνῶν</strong> (for the obedience of the Gentiles) — the same <em>eis hypakoēn</em> frame as 1:5; the missionary goal is framed as covenant allegiance (obedience of faith).</p>',
    "19": '<p><strong>ἐν δυνάμει σημείων καὶ τεράτων</strong> (in the power of signs and wonders, G4592/G5059) — the pairing <em>sēmeia kai terata</em> is the standard OT phrase for miraculous acts accompanying divine missions (Exod 7:3; Deut 6:22); Paul claims this category for his apostolic mission. <strong>κεκληρωκέναι</strong> (perfect active infinitive of G2820, to complete/fulfill) — the perfect tense is significant: Paul\'s encirclement of the eastern Mediterranean with the gospel is presented as a completed mission in those regions, not an ongoing one. <strong>ἀπὸ Ἰερουσαλὴμ... μέχρι τοῦ Ἰλλυρικοῦ</strong> (from Jerusalem to Illyricum) — the geographical arc traces the actual mission; Illyricum is the northwest Balkan region, the farthest point Paul had reached.</p>',
    "20": '<p><strong>φιλοτιμούμενον</strong> (G5389, making it my ambition) — a significant word; <em>philotimeomai</em> means to seek honor in a particular direction, to aspire deliberately; it is an honorable ambition rather than mere preference. <strong>εὐαγγελίζεσθαι οὐχ ὅπου ὠνομάσθη Χριστός</strong> (to proclaim the gospel where Christ has not been named) — aorist passive <em>ōnomasthē</em> (was named); the criterion for Paul\'s geographical planning is not institutional but pioneering: unplanted rather than unwatered. <strong>ἐπ᾽ ἀλλότριον θεμέλιον οἰκοδομῶ</strong> (I am building on another\'s foundation) — the construction metaphor Paul uses at 1 Cor 3:10 for the relationship between apostles and subsequent teachers.</p>',
    "21": '<p>Paul quotes Isa 52:15 LXX — <strong>ὄψονται, οἷς οὐκ ἀνηγγέλη</strong> (those who were not told will see) — as the scriptural warrant for his pioneer-mission strategy. Isaiah\'s Servant Song announces that kings will be silenced and see what they had not been told; Paul reads the Servant\'s mission as defining the scope of his own: going where the message has not yet gone. The scriptural grounding of his missional method is consistent with the letter\'s argument that the gospel\'s reach is scripturally anticipated.</p>',
    "22": '<p><strong>τὰ πολλὰ ἐνεκοπτόμην</strong> (I was often/repeatedly hindered, G1465) — the imperfect passive indicates repeated action in the past; the hindering was not a single obstacle but a pattern. Paul does not specify the hindrance; it may be providential direction (cf. Acts 16:6-7), competing ministry demands, or adversarial opposition.</p>',
    "23": '<p><strong>μηκέτι τόπον ἔχων ἐν τοῖς κλίμασιν τούτοις</strong> (no longer having place in these regions, G5117) — the "place" is the available space for pioneer proclamation; once the gospel is planted, Paul\'s work in that region is complete. <strong>ἐπιποθίαν δὲ ἔχων τοῦ ἐλθεῖν πρὸς ὑμᾶς ἀπὸ πολλῶν ἐτῶν</strong> (having a deep longing to come to you for many years, G1972) — <em>epipothia</em> is an intensified form of longing, beyond ordinary desire; the duration (many years) underlines the genuineness.</p>',
    "24": '<p><strong>θεάσωμαι ὑμᾶς</strong> (behold/see you, G2300) — <em>theaomai</em> has a richer visual dimension than the plain <em>horaō</em>; it suggests a purposeful beholding rather than a passing sight. <strong>ὑμῶν προπεμφθῆναι ἐκεῖ</strong> (to be sent forward/assisted by you, G4311) — <em>propempō</em> is a technical term for the practical support (provisions, letters, travel companions) that a community provided for an itinerant missionary at departure.</p>',
    "25": '<p><strong>διακονῶν τοῖς ἁγίοις</strong> (serving the saints, G1247) — present participle indicating the ongoing current activity that delays the Roman visit. The same <em>diakoneo</em> root appears throughout ch.15 (v.8 Christ as diakonos, v.16 Paul as leitourgos, 16:1 Phoebe as diakonos); the term has both formal and informal service dimensions.</p>',
    "26": '<p><strong>κοινωνίαν τινὰ ποιήσασθαι</strong> (to make a contribution/fellowship, G2842) — <em>koinōnia</em> carries both the spiritual dimension (participation, fellowship) and the practical (the financial sharing that expresses it). The same word Paul uses for the Lord\'s Supper in 1 Cor 10:16. <strong>εἰς τοὺς πτωχοὺς τῶν ἁγίων</strong> (for the poor among the saints) — the poverty is specific to Jerusalem; the collection is an act of Gentile solidarity with the mother community.</p>',
    "27": '<p><strong>ὀφείλουσιν</strong> (they owe it, G3784) — the same obligation-verb as 15:1 (we are obligated); obligation here is not legal but covenantal and relational. <strong>τοῖς πνευματικοῖς αὐτῶν ἐκοινώνησαν</strong> (they shared in their spiritual things, G2841) — the reciprocity Paul identifies is ontological and economic: Gentiles received spiritual inheritance through Jewish covenant; Jews now receive material support from Gentiles. The sharing (koinōnōnō) is the same root as koinōnia in v.26.</p>',
    "28": '<p><strong>σφραγισάμενος αὐτοῖς τὸν καρπὸν τοῦτον</strong> (having sealed this fruit to them, G4972) — <em>sphragizō</em> is the verb for sealing as certification of delivery; Paul is treating the collection as a sealed consignment to be formally handed over. <strong>καρπόν</strong> (fruit, G2590) — the mission-harvest term (cf. 1:13; 15:20); the Jerusalem collection is itself described as fruit, implying it is the legitimate yield of the Gentile mission.</p>',
    "29": '<p><strong>ἐν πληρώματι εὐλογίας Χριστοῦ</strong> (in the fullness of the blessing of Christ) — <em>plēroma</em> (G4138) is Paul\'s fullness-word; the blessing he will bring is not partial or provisional but complete. This confidence is grounded in Christ\'s provision, not Paul\'s preparation.</p>',
    "30": '<p><strong>συναγωνίσασθαί μοι</strong> (to strive together with me, G4865) — the compound verb is from the arena; prayer is framed as athletic contest requiring real effort alongside the one praying. <strong>ἐν ταῖς προσευχαῖς ὑπὲρ ἐμοῦ πρὸς τὸν θεόν</strong> (in prayers on my behalf to God) — the double prepositions specify both direction (toward God) and beneficiary (on my behalf). <strong>διὰ τῆς ἀγάπης τοῦ πνεύματος</strong> (by/through the love of the Spirit, G4151 disp=3) — the genitive is probably subjective: the love that the Spirit generates in the community becomes the motivating ground of their prayer-striving.</p>',
    "31": '<p><strong>ῥυσθῶ ἀπὸ τῶν ἀπειθούντων ἐν τῇ Ἰουδαίᾳ</strong> (that I may be delivered from the unbelieving/disobedient ones in Judea, G544) — <em>apeithountes</em> = those who disobey, refuse to be persuaded; the same root as 11:30-32 where it describes Gentile and Jewish disobedience. Paul\'s prayer request anticipates the actual opposition he will face in Jerusalem (Acts 21:27-36). <strong>ἡ διακονία</strong> (the ministry/service, G1248) — the collection for Jerusalem is elevated to the status of a formal ministry.</p>',
    "32": '<p><strong>ἵνα ἐν χαρᾷ ἐλθὼν πρὸς ὑμᾶς διὰ θελήματος θεοῦ</strong> (that coming to you with joy by God\'s will) — <em>dia thelēmatos theou</em> qualifies the arrival as conditional on divine permission; the joy is the anticipated texture of a visit completed under favorable conditions. <strong>συναναπαύσωμαι ὑμῖν</strong> (I may be refreshed/rested together with you, G4875) — the compound verb implies mutual refreshment; Paul anticipates the visit as mutually restorative, not merely ministerially productive (cf. 1:12).</p>',
    "33": '<p><strong>ὁ θεὸς τῆς εἰρήνης</strong> (the God of peace, G1515) — the last in the series of divine-character titles in this chapter (God of endurance v.5, God of hope v.13); this one is both a closing blessing and a forward pointer to 16:20 where the same title appears with eschatological content ("will soon crush Satan"). The peace Paul invokes is not merely relational but the comprehensive OT <em>shalom</em> — wholeness and right ordering.</p>'
  },
  "16": {
    "1": '<p><strong>Φοίβην τὴν ἀδελφὴν ἡμῶν</strong> (Phoebe our sister) — the kinship designation <em>adelphē</em> marks full membership in the covenant community, not a subordinate category. <strong>οὖσαν καὶ διάκονον τῆς ἐκκλησίας</strong> (who is also a deacon/servant of the church, G1249) — <em>diakonos</em> has no feminine form in Greek; it applies without modification to Phoebe. The word is used for Christ in 15:8, for Paul in 1 Cor 3:5, and for community officers in Phil 1:1 and 1 Tim 3:8. The same term for the same role, regardless of the referent\'s gender.</p>',
    "2": '<p><strong>ἀξίως τῶν ἁγίων</strong> (in a manner worthy of the saints) — the genitive of standard: the quality of reception is calibrated to what membership in the holy people deserves. <strong>προστάτις πολλῶν ἐγενήθη καὶ ἐμοῦ αὐτοῦ</strong> (she has been a patron/helper of many and of me myself, G4368) — <em>prostatis</em> (G4368) is the feminine of <em>prostates</em>, a term from civic life for a patron or sponsor who provides legal support and financial backing for persons lacking status. Paul explicitly names himself as among her beneficiaries, confirming the substantive nature of the role.</p>',
    "3": '<p><strong>Πρίσκαν καὶ Ἀκύλαν</strong> (Priscilla and Aquila) — Priscilla is named first; across the six NT references to this couple, she is named first in four. Ancient convention generally placed higher-status individuals first; the consistent pattern likely reflects her leadership role. <strong>τοὺς συνεργούς μου ἐν Χριστῷ Ἰησοῦ</strong> (my co-workers in Christ Jesus, G4904) — <em>synergos</em> is Paul\'s term for collaborative ministry partners (cf. Phil 4:3; 1 Thess 3:2); applied equally here to Priscilla and Aquila together.</p>',
    "4": '<p><strong>τὸν ἑαυτῶν τράχηλον ὑπέθηκαν</strong> (they laid down their own necks, G5137) — an idiom for risking execution; the image is of baring one\'s throat to a blade. The reflexive <em>heautōn</em> emphasizes the personal cost. <strong>πᾶσαι αἱ ἐκκλησίαι τῶν ἐθνῶν</strong> (all the churches of the Gentiles) — a broad acknowledgment indicating that Priscilla and Aquila\'s sacrifice was known and appreciated across the Pauline network.</p>',
    "5": '<p><strong>τὴν κατ᾽ οἶκον αὐτῶν ἐκκλησίαν</strong> (the church in their house, G1577) — the house-church is the primary organizational unit of early Christianity; there is no dedicated church building in this period. <strong>ἀπαρχὴν τῆς Ἀσίας</strong> (first fruit of Asia, G536) — the same term Paul uses for the Spirit (8:23) and for the resurrection (1 Cor 15:20); applying it to an individual describes Epaenetus as the initial yield of the gospel harvest in the province, consecrating the whole to God.</p>',
    "6": '<p><strong>ἥτις πολλὰ ἐκοπίασεν εἰς ὑμᾶς</strong> (who labored much for you, G2872) — <em>kopiaō</em> is Paul\'s word for intensive labor (used for agricultural and manual work); it appears frequently in his accounts of apostolic ministry (1 Cor 15:10; Gal 4:11; Phil 2:16). The application of this term to Mary affirms the substantive and effortful nature of her contribution to the Roman community.</p>',
    "7": '<p><strong>Ἀνδρόνικον καὶ Ἰουνίαν</strong> (Andronicus and Junia) — the second name is almost certainly <em>Iounian</em> (accusative of <em>Iounia</em>, a common Roman female name) rather than <em>Iounian</em> (accusative of the unattested male name <em>Iounias</em>); the female reading is supported by the standard Greek accent and by the absence of the name Junias in any ancient source. <strong>ἐπίσημοι ἐν τοῖς ἀποστόλοις</strong> (outstanding among the apostles) — the phrase is debated: either (a) notable/distinguished within the group of apostles, or (b) well-known in the eyes of the apostles. Option (a) would make Junia an apostle; option (b) would not. The lexical parallel with other <em>en</em>-constructions favors the inclusive reading.</p><p><strong>οἳ καὶ πρὸ ἐμοῦ γέγοναν ἐν Χριστῷ</strong> (who also were in Christ before me) — the perfect tense <em>gegonasin</em> indicates a state persisting from before Paul\'s conversion; they are senior to him in the faith.</p>',
    "8": '<p><strong>τὸν ἀγαπητόν μου ἐν κυρίῳ</strong> (my beloved in the Lord) — the <em>en kyriō</em> qualifier is consistent throughout the greeting list; it specifies that the love and relationship is grounded in their shared belonging to Christ, not merely social affinity.</p>',
    "9": '<p><strong>Οὐρβανὸν τὸν συνεργὸν ἡμῶν ἐν Χριστῷ</strong> (Urbanus our co-worker in Christ) — the <em>synergos</em> title again (cf. v.3); its consistent use marks those who have participated directly in the gospel mission alongside Paul.</p>',
    "10": '<p><strong>τὸν δόκιμον ἐν Χριστῷ</strong> (the approved/tested one in Christ, G1384) — <em>dokimos</em> (the positive of <em>adokimos</em>, the disqualified mind of 1:28) means one who has stood the test, proven genuine. <strong>τοὺς ἐκ τῶν Ἀριστοβούλου</strong> (those from the household of Aristobulus) — not Aristobulus himself (who may not have been a believer) but members of his household.</p>',
    "11": '<p><strong>τὸν συγγενῆ μου</strong> (my kinsman/fellow Jew, G4773) — <em>syngenēs</em> can mean blood relative or ethnic kin (fellow Jew); given the usage pattern in this section, ethnic kinship (fellow Jew) is more likely.</p>',
    "12": '<p><strong>Τρύφαιναν καὶ Τρυφῶσαν τὰς κοπιώσας ἐν κυρίῳ</strong> (Tryphena and Tryphosa, those who work hard in the Lord, G2872) — <em>kopiaousas</em> (present participle) again: both women are characterized by ongoing labor in the community. The names mean "dainty/soft" (Tryphena) and "delicate" (Tryphosa) — possibly sisters, given the similar names. <strong>Περσίδα τὴν ἀγαπητήν, ἥτις πολλὰ ἐκοπίασεν ἐν κυρίῳ</strong> (beloved Persis, who labored much in the Lord) — the aorist <em>ekopiasein</em> for Persis vs. present participle for Tryphena/Tryphosa may indicate that Persis\'s intensive work was in the past, while the others\' continues.</p>',
    "13": '<p><strong>Ῥοῦφον τὸν ἐκλεκτὸν ἐν κυρίῳ</strong> (Rufus, the chosen one in the Lord, G1588) — <em>eklektos</em> (elect/chosen) is the standard term for divine election; whether it is a common designation here for any believer or a specific honorific is unclear. <strong>τὴν μητέρα αὐτοῦ καὶ ἐμοῦ</strong> (his mother and mine) — the biological mother of Rufus who has functioned as a mother to Paul; a profound statement of the re-family that the new covenant creates.</p>',
    "14": '<p>The four names in v.14 are followed by <strong>τοὺς σὺν αὐτοῖς ἀδελφούς</strong> (the brothers/siblings with them) — indicating a house-church or small group attached to these individuals. The pattern repeats in v.15. Multiple overlapping house-churches in Rome (vv.5, 10, 11, 14, 15) reflects the decentralized social organization of the Roman church.</p>',
    "15": '<p>The greeting to Philologus, Julia, Nereus, his sister, and Olympas concludes the individual and household greetings. <strong>πάντων τῶν ἁγίων τῶν σὺν αὐτοῖς</strong> (all the saints with them) — the community Paul is addressing is distributed across multiple households; the letter functions as communication to the whole network.</p>',
    "16": '<p><strong>φιλήματι ἁγίῳ</strong> (with a holy kiss, G5370) — the greeting practice appears in all four major Pauline letters (1 Cor 16:20; 2 Cor 13:12; 1 Thess 5:26); its designation as "holy" distinguishes it from secular social kissing by marking it as a covenant-community act. <strong>αἱ ἐκκλησίαι πᾶσαι τοῦ Χριστοῦ</strong> (all the churches of Christ) — the final greeting extends the apostolic network\'s endorsement to the Roman community.</p>',
    "17": '<p><strong>σκοπεῖν τοὺς τὰς διχοστασίας καὶ τὰ σκάνδαλα ποιοῦντας</strong> (watch out for those making divisions and stumbling blocks, G1370/G4625) — <em>skopeō</em> (G4648) is attentive watching, not passive observation; <em>dichostasia</em> (divisions) and <em>skandala</em> (stumbling-blocks, traps) are the double threat. <strong>παρὰ τὴν διδαχὴν ἣν ὑμεῖς ἐμάθετε</strong> (contrary to the teaching you learned) — the aorist <em>emathete</em> treats the received teaching as the stable norm against which deviations are measured.</p>',
    "18": '<p><strong>τῇ ἑαυτῶν κοιλίᾳ δουλεύουσιν</strong> (they are enslaved to their own belly/appetite, G2836) — <em>koilia</em> (stomach/belly) is used contemptuously for self-indulgent, appetite-driven behavior (cf. Phil 3:19); these teachers serve their own material interests under religious cover. <strong>χρηστολογίας καὶ εὐλογίας</strong> (smooth talk and flattery, G5543/G2129) — <em>chrēstologia</em> is a rare compound (G5543) meaning plausible, fair-sounding speech; <em>eulogia</em> here in the unusual negative sense of fine-sounding empty praise. The two terms describe the rhetorical technique of the troublemakers.</p>',
    "19": '<p><strong>ἐφ᾽ ὑμῖν χαίρω</strong> (I rejoice over/because of you) — <em>epi</em> + dative marks the ground of joy: the Roman community\'s obedience itself. <strong>θέλω δὲ ὑμᾶς σοφοὺς εἶναι εἰς τὸ ἀγαθόν</strong> (but I want you to be wise for good) — the infinitive construction specifies the direction of wisdom: toward good rather than merely smart. <strong>ἀκεραίους δὲ εἰς τὸ κακόν</strong> (innocent/unmixed regarding evil, G185) — <em>akeraios</em> means unadulterated, unmixed; the image is of undiluted material not contaminated by evil.</p>',
    "20": '<p><strong>ὁ θεὸς τῆς εἰρήνης συντρίψει τὸν Σατανᾶν ὑπὸ τοὺς πόδας ὑμῶν ἐν τάχει</strong> (the God of peace will soon crush Satan under your feet) — <em>syntribō</em> (G4937) is a strong crushing verb; <em>en tachei</em> (speedily, soon) indicates near-future eschatological expectation. This alludes to Gen 3:15 (the head of the serpent crushed); Paul applies the promise to the community\'s cosmic struggle with the adversary. The God of peace crushing the adversary is not paradoxical: peace requires the defeat of what opposes it.</p>',
    "21": '<p><strong>Τιμόθεος ὁ συνεργός μου</strong> (Timothy my co-worker, G4904) — the first of the sender\'s greetings from Paul\'s companions; <em>synergos</em> used for Timothy as in v.3 for Priscilla and Aquila. <strong>Λούκιος καὶ Ἰάσων καὶ Σωσίπατρος οἱ συγγενεῖς μου</strong> (Lucius, Jason, and Sosipater, my kinsmen) — the kinship designation likely means fellow Jews (cf. v.11) rather than blood relatives.</p>',
    "22": '<p><strong>ἐγὼ Τέρτιος ὁ γράψας τὴν ἐπιστολὴν</strong> (I, Tertius, who wrote the letter) — a rare moment when the professional scribe (<em>amanuensis</em>) identifies himself; Paul would have dictated and Tertius wrote. The phrase <strong>ἐν κυρίῳ</strong> (in the Lord) characterizes Tertius\'s own greeting, indicating he was a believer, not merely a hired secretary.</p>',
    "23": '<p><strong>Γάϊος ὁ ξένος μου καὶ ὅλης τῆς ἐκκλησίας</strong> (Gaius my host and of the whole church, G3581) — <em>xenos</em> here means host (one who receives guests), not stranger; Gaius\'s house served as Paul\'s base and the gathering place for the whole church in Corinth. <strong>Ἔραστος ὁ οἰκονόμος τῆς πόλεως</strong> (Erastus the city treasurer/steward, G3623) — <em>oikonomos tēs poleōs</em> is the financial administrator of the city; an inscription found at Corinth mentions an Erastus who paved a street at his own expense. If the same person, his conversion is socially significant.</p>',
    "24": '<p><strong>ἡ χάρις τοῦ κυρίου ἡμῶν Ἰησοῦ Χριστοῦ</strong> (the grace of our Lord Jesus Christ) — the standard Pauline benediction; some manuscripts omit v.24 as textually suspect (it may be a scribal insertion assimilating to the Thessalonian epistles). The doxology that follows (vv.25-27) is the letter\'s formal close.</p>',
    "25": '<p><strong>τῷ δὲ δυναμένῳ ὑμᾶς στηρίξαι</strong> (now to him who is able to establish you, G4741) — the doxology opens with the divine capacity to do what Paul has been praying for throughout the letter (cf. 1:11). <strong>κατὰ τὸ εὐαγγέλιόν μου καὶ τὸ κήρυγμα Ἰησοῦ Χριστοῦ</strong> (according to my gospel and the proclamation of Jesus Christ) — the dual genitive: the gospel as Paul proclaims it, and the proclamation whose content is Jesus Christ. <strong>κατὰ ἀποκάλυψιν μυστηρίου χρόνοις αἰωνίοις σεσιγημένου</strong> (according to the revelation of mystery silent in ages past, G3466) — <em>mystērion</em> in Paul is not an esoteric secret but a divinely hidden plan now disclosed; <em>sesigēmenou</em> (perfect passive participle = having been kept silent) emphasizes the completed divine concealment now ending.</p>',
    "26": '<p><strong>φανερωθέντος δὲ νῦν</strong> (but now having been disclosed, G5319) — the aorist passive marks the disclosure as the eschatological event; <em>nyn</em> is the same temporal marker as 3:21 (<em>nyni</em> = but now). <strong>διά τε γραφῶν προφητικῶν</strong> (also through prophetic writings) — the mystery is disclosed both through the gospel event and through the OT Scriptures; the letter\'s entire argument about the Law and Prophets bearing witness (3:21) is here summarized. <strong>εἰς ὑπακοὴν πίστεως</strong> (for the obedience of faith) — the closing bracket of the letter\'s framing (cf. 1:5); the same phrase that described Paul\'s mission purpose in the salutation now describes the goal of the mystery\'s disclosure to all nations.</p>',
    "27": '<p><strong>μόνῳ σοφῷ θεῷ</strong> (to the only wise God) — the dative of indirect object of the glory-ascription. <em>Monō sophō</em> (only wise) contrasts the transcendent wisdom of God with the pretended wisdom of 1:22 ("claiming to be wise, they became fools"). The letter closes where it began: the gospel as the disclosure of divine wisdom to those who were without excuse before God\'s wisdom in creation. <strong>διὰ Ἰησοῦ Χριστοῦ</strong> (through Jesus Christ) — the mediatorial role persists even in the doxological address; glory reaches God through and in Christ, not apart from him.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 15–16 mkt-original written.')

if __name__ == '__main__':
    main()
